const GEAR_DATA = [...RACKETS_DATA, ...SHOES_DATA, ...STRINGS_DATA];

export const seedGear = async (force = false) => {
  try {
    const gearCol = collection(db, 'gear');
    const snapshot = await getDocs(gearCol);
    
    if (!snapshot.empty && force) {
      console.log('Clearing existing gear data...');
      const batch = writeBatch(db);
      snapshot.docs.forEach((doc) => {
        batch.delete(doc.ref);
      });
      await batch.commit();
    }

    const newSnapshot = await getDocs(gearCol);
    if (newSnapshot.empty || force) {
      console.log('Seeding gear data...');
      
      // Firestore batch limit is 500. Split GEAR_DATA into chunks.
      const CHUNK_SIZE = 500;
      for (let i = 0; i < GEAR_DATA.length; i += CHUNK_SIZE) {
        const chunk = GEAR_DATA.slice(i, i + CHUNK_SIZE);
        const batch = writeBatch(db);
        
        chunk.forEach((item) => {
          const newDocRef = doc(gearCol);
          batch.set(newDocRef, item);
        });
        
        await batch.commit();
        console.log(`Batch ${Math.floor(i / CHUNK_SIZE) + 1} committed.`);
      }
      
      console.log('Gear data seeded successfully!');
      return { success: true, message: `Successfully seeded ${GEAR_DATA.length} items.` };
    }
    return { success: false, message: 'Gear data already exists. Use force to overwrite.' };
  } catch (error) {
    console.error('Error seeding gear data:', error);
    return { success: false, message: error instanceof Error ? error.message : 'Unknown error' };
  }
};

export const seedDatabase = async () => {
  console.log('seedDatabase called');
  return true;
};

export const removeSeedData = async () => {
  console.log('removeSeedData called');
  return true;
};
